class_basic:
classDiagram
    class Animal {
        +String name
        +int age
        +makeSound() void
    }
    class Dog {
        +String breed
        +fetch() void
    }
    Animal <|-- Dog

class_interfaces:
classDiagram
    class Shape {
        <<interface>>
        +draw() void
        +area() float
    }
    class Circle {
        +float radius
        +draw() void
        +area() float
    }
    class Rectangle {
        +float width
        +float height
        +draw() void
        +area() float
    }
    Shape <|.. Circle
    Shape <|.. Rectangle

class_annotations:
classDiagram
    class Shape {
        <<abstract>>
        +color: String
        +draw() void
    }
    class Color {
        <<enumeration>>
        RED
        GREEN
        BLUE
    }

